import React from 'react';
import './world-map.css';
import map1 from './louth.json'; // Import your map data files
import map2 from './offaly.json';
import map3 from './maps.json';

const maps = [map1.mapData, map2.mapData, map3.mapData]; // Array of map data

class Overworld extends React.Component {
  constructor(props) {
    super(props);

    this.state = {
      currentMapIndex: 0, // Index of the current map in the array
    };
  }

  handleTile3Click = () => {
    // Toggle to the next map in the array
    this.setState((prevState) => ({
      currentMapIndex: (prevState.currentMapIndex + 1) % maps.length,
    }));
  };

  render() {
    const { currentMapIndex } = this.state;
    const currentMap = maps[currentMapIndex];

    return (
      <div className="world-map-container">
        <button onClick={this.handleTile3Click}>Toggle Map</button>
        <div className="world-map">
          {currentMap.map((row, rowIndex) => (
            <div key={`row-${rowIndex}`} className="map-row">
              {row.map((tile, colIndex) => (
                <div key={`col-${colIndex}`} className={`map-tile tile-${tile}`}>
                  {tile}
                </div>
              ))}
            </div>
          ))}
        </div>
      </div>
    );
  }
}

export default Overworld;
